const statsRaw = $('Fetch Block Stats (7 days)').first().json;
const stats = statsRaw?.data?.result?.data || statsRaw?.data || (Array.isArray(statsRaw) ? statsRaw : []);

// Get CRM data (depositors + revenue by block)
let crmMap = {};
try {
  const crmRows = $('Fetch CRM Block Stats').all().map(i => i.json);
  crmRows.forEach(r => {
    if (r.block_id) {
      crmMap[String(r.block_id)] = {
        leads: Number(r.total_leads) || 0,
        depositors: Number(r.depositors) || 0,
        crm_revenue: Number(r.crm_revenue) || 0
      };
    }
  });
} catch (e) {
  // CRM data not available, continue with Geozo data only
}

if (!Array.isArray(stats)) {
  return [{ json: { error: 'No block stats' } }];
}

// Aggregate Geozo stats by block_id
const blockAgg = {};
stats.forEach(s => {
  const blockId = String(s.block_id);
  if (!blockId) return;
  if (!blockAgg[blockId]) {
    blockAgg[blockId] = { spend: 0, geozo_revenue: 0, clicks: 0, shows: 0, ads: new Set() };
  }
  blockAgg[blockId].spend += s.money || 0;
  blockAgg[blockId].geozo_revenue += s.postbacks_confirmed_money || 0;
  blockAgg[blockId].clicks += s.clicks_count || 0;
  blockAgg[blockId].shows += s.shows_count || 0;
  if (s.ad_id) blockAgg[blockId].ads.add(s.ad_id);
});

const blacklist = [];
const whitelist = [];
const yellow = [];

for (const [blockId, b] of Object.entries(blockAgg)) {
  const crm = crmMap[blockId] || { leads: 0, depositors: 0, crm_revenue: 0 };

  // Use CRM revenue if available, otherwise fall back to Geozo postbacks
  const revenue = crm.crm_revenue > 0 ? crm.crm_revenue : b.geozo_revenue;
  const roi = b.spend > 0 ? ((revenue - b.spend) / b.spend * 100) : 0;
  const ctr = b.shows > 0 ? (b.clicks / b.shows * 100) : 0;
  const cr = crm.leads > 0 ? (crm.depositors / crm.leads * 100) : 0;

  const blockInfo = {
    block_id: blockId,
    roi: Math.round(roi * 100) / 100,
    ctr: Math.round(ctr * 10000) / 10000,
    cr: Math.round(cr * 100) / 100,
    clicks: b.clicks,
    shows: b.shows,
    spend: Math.round(b.spend * 100) / 100,
    revenue: Math.round(revenue * 100) / 100,
    crm_leads: crm.leads,
    crm_depositors: crm.depositors,
    ad_count: b.ads.size,
    data_source: crm.crm_revenue > 0 ? 'crm' : 'geozo'
  };

  // GREEN: profitable block (CRM ROI > 15% with depositors, or Geozo ROI > 20%)
  if (crm.depositors > 0 && roi > 15 && b.clicks > 10) {
    blockInfo.classification = 'green';
    whitelist.push(blockInfo);
  }
  else if (roi > 20 && b.clicks > 10 && ctr > 0.5) {
    blockInfo.classification = 'green';
    whitelist.push(blockInfo);
  }
  // RED: losing block (high spend, no depositors from CRM)
  else if (crm.leads >= 10 && crm.depositors === 0 && b.spend > 5) {
    blockInfo.classification = 'red';
    blacklist.push(blockInfo);
  }
  else if ((roi < -30 && b.clicks > 20) || (ctr < 0.1 && b.shows > 500)) {
    blockInfo.classification = 'red';
    blacklist.push(blockInfo);
  }
  // YELLOW: observation
  else {
    blockInfo.classification = 'yellow';
    yellow.push(blockInfo);
  }
}

return [{
  json: {
    blacklist_blocks: blacklist.map(b => b.block_id),
    whitelist_blocks: whitelist.map(b => b.block_id),
    blacklist_details: blacklist,
    whitelist_details: whitelist,
    yellow_details: yellow,
    total_analyzed: Object.keys(blockAgg).length,
    crm_blocks_matched: Object.keys(crmMap).length
  }
}];

const blockData = $('Classify Blocks').first().json;
const adsRaw = $('Fetch Active Ad Groups').first().json;
const ads = adsRaw?.data?.result?.data || adsRaw?.data || (Array.isArray(adsRaw) ? adsRaw : []);

// Get unique ad_group_ids
const adGroupIds = [...new Set((Array.isArray(ads) ? ads : []).map(a => a.ad_group_id).filter(Boolean))];

if (adGroupIds.length === 0) {
  return [{ json: { action: 'SKIP', reason: 'No ad groups found' } }];
}

// Prepare updates for each ad group
return adGroupIds.map(agId => ({
  json: {
    ad_group_id: agId,
    blacklist_blocks: blockData.blacklist_blocks,
    whitelist_blocks: blockData.whitelist_blocks,
    blacklist_count: blockData.blacklist_blocks.length,
    whitelist_count: blockData.whitelist_blocks.length,
    total_analyzed: blockData.total_analyzed
  }
}));

